// Stub declarations for Vue-2-only / untyped packages, so `.ts` files can
// import them without "could not find a declaration file" errors. Each becomes
// `any`. Replace with real types (or @types/*) as a package gains them.
declare module 'vue-cookie'
declare module 'vue-moment'
declare module 'vuelidate'
declare module 'vuelidate/lib/validators'
declare module 'vue-select'
declare module 'papaparse'
declare module 'vue2-form-loading'
declare module 'vue-input-tag'
declare module '@johmun/vue-tags-input'
declare module 'pulltorefreshjs'
